// src/components/LeanConnect.tsx
import React, { useState } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:3001';

// Declare the Lean global variable (TypeScript type)
declare global {
    interface Window {
        Lean: any;
    }
}

interface LeanConnectProps {
    customerId: string;
    onSuccess: (entityId: string) => void;
    onError: (error: string) => void;
}

const LeanConnect: React.FC<LeanConnectProps> = ({ customerId, onSuccess, onError }) => {
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<string>('');

    const handleConnect = async () => {
        setLoading(true);
        setStatus('Connecting to Lean...');

        try {
            // Step 1: Get the customer-scoped token from your backend
            const tokenResponse = await axios.get(`${API_URL}/api/lean/customer-token`, {
                params: { customerId }
            });

            if (!tokenResponse.data.success) {
                throw new Error('Failed to get customer token: ' + tokenResponse.data.error);
            }

            const customerToken = tokenResponse.data.customerToken;
            console.log('✅ Customer token received');

            // Step 2: Get your app token from environment variables
            const appToken = '730a9f67-7149-49e5-988d-30200b8fa695'; // ← Your LEAN_APP_ID

            // Step 3: Call Lean.connect() — this opens the bank selection modal
            window.Lean.connect({
                access_token: customerToken,           // ← Customer-scoped token
                app_token: appToken,                   // ← Your application token
                customer_id: customerId,               // ← Your customer ID
                permissions: ['identity', 'accounts', 'balance', 'transactions'],
                sandbox: true,                        // ← IMPORTANT: Use sandbox mode
                debug: true                           // ← Enable logging
            });

            setStatus('Waiting for bank authorization...');

            // Step 4: Handle Lean's callback response
            window.Lean.callback = (response: any) => {
                console.log('📨 Lean callback:', response);

                if (response.status === 'SUCCESS') {
                    // The entity was created!
                    setStatus('✅ Bank connected successfully!');
                    onSuccess(response.message || 'Success');
                } else if (response.status === 'ERROR') {
                    setStatus('❌ Failed: ' + response.message);
                    onError(response.message || 'Failed to connect bank');
                } else if (response.status === 'CANCEL') {
                    setStatus('⏹️ User cancelled');
                }

                setLoading(false);
            };

        } catch (error: any) {
            console.error('❌ Lean connect error:', error);
            setStatus('❌ Error: ' + error.message);
            onError(error.message || 'Failed to initiate bank connection');
            setLoading(false);
        }
    };

    return (
        <div className="lean-connect">
            <button
                onClick={handleConnect}
                disabled={loading}
                className="btn-connect"
            >
                {loading ? '⏳ Connecting...' : '🔗 Connect Bank Account'}
            </button>
            {status && <p className="lean-status">{status}</p>}
        </div>
    );
};

export default LeanConnect;
